Here is a C++ function to perform RLE (Run Length Encoding) compression, given a positive counter to indicate the number of compressed `float`s, and a negative counter to indicate the number of uncompressed `float`s:
void RLECompress(float *input, int *counter, int N) {
    int run = 0, i;
    while (run < N) {
        int length = 1;
        for (i = 0; i < counter[run]; i++) {
            length++;
        }
        counter[run] = length;
        run++;
    }
    while (run > 0) {
        int length = 1;
        for (i = 0; i < counter[run - 1]; i++) {
            length++;
        }
        counter[run - 1] = length;
        run--;
    }
}
